            E = expected[category]
            if E > 0:
                contribution = ((O - E) ** 2) / E
                chi_square += contribution
                print(f"  {hist_type} {category}: O={O}, E={E:.2f}, χ²={contribution:.4f}")

    return chi_square, expected_table

